import{c as t,Q as a,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Ben's Bites — 2026-05-09","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-09","date":"2026-05-09T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-09-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-09-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-05/2026-05-09-bens-bites.md"};function o(i,e,l,h,p,c){return a(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="🍔-ben-s-bites-—-2026-05-09" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-09 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-09" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-09&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="elon-doubled-limits" tabindex="-1"><a href="https://www.bensbites.com/p/elon-doubled-limits" target="_blank" rel="noreferrer">Elon doubled limits</a> <a class="header-anchor" href="#elon-doubled-limits" aria-label="Permalink to &quot;[Elon doubled limits](https://www.bensbites.com/p/elon-doubled-limits)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-07</em></p><p>Hey folks,</p><p>I&#39;m a professional procrastinator -- I need to ship this course and re-write my fundraising deck for fund II, buuuut yesterday I finally built something I&#39;ve wanted for a while.</p><p>I loved Superhuman, I used it for many years ($40/mo!) but all I really loved was split inboxes based on labels, and how quick and nice it is to use.</p><p>I don&#39;t need (…yet? ever?) AI to read all my emails, draft replies, chase me to do things and be a PA for me, I&#39;ve had PA&#39;s and I always let them go.</p><p>I just want email rules - if this address is labelled &#39;pitch&#39; (for PR pitches), archive it. If no label - it&#39;s &#39;important&#39; and needs a reply for me, if &#39;investing&#39; it&#39;s from an LP or portfolio founder, if &#39;newsletter&#39; archive it (don&#39;t do this or you wont see these! 😊).</p><p>Gmail has filters and labels but it&#39;s limited and just can&#39;t give me the UI I want to work in. So naturally, I built my own. I&#39;ll send a &#39;Ben&#39;s Builds&#39; email on Saturday with more details on what I actually did. It took me ~2 hours for the first version.</p><p>I was &#39;pushed&#39; to this by seeing Dan Shipper&#39;s <a href="https://x.com/every/status/2051703753930309979" target="_blank" rel="noreferrer">Codex-native email workflow</a> - but again, I don&#39;t need most of the stuff he&#39;s doing. Email is very different for everyone. But now I can completely customise my experience…If I want daily briefs to summarise all my newsletters - my agent can do it, if I want automated actions - my agent can, and so on.</p><p>So if you send me an email, it is me who will reply - but my agent may have you labelled and organised to make it easier for me to respond.</p><p>Personal software can be built by anyone!</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Attio</a></em></p><blockquote><p>GTM Atlas is the map for modern go-to-market.</p><p>Written by top operators, Atlas is a free resource covering the full customer journey, with systems thinking that scales with you.</p><p>Curated by Attio. Mapped by operators.</p><p><a href="https://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Read now</a></p></blockquote><p>Fun fact: Attio&#39;s founder, Nicolas was interviewed by me in Sept 2020 for my previous company&#39;s podcast. <a href="https://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Attio</a> is very good software!! I should&#39;ve invested at the time 😩. But for now… I&#39;m going to build something with it 😈</p><hr><h4 id="headlines" tabindex="-1">Headlines <a class="header-anchor" href="#headlines" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li>Free users in ChatGPT are now on &quot;<strong><a href="https://openai.com/index/gpt-5-5-instant/" target="_blank" rel="noreferrer">GPT-5.5 Instant</a></strong> &quot; - a new model that replaces GPT-5.3 Instant. It&#39;s significantly better at vision, understanding PDFs, web search and using your memories and past chats smartly. Its responses are also shorter in general with less emojis. It also hallucinates 52.5% less than the previous model on high-stakes prompts.</li></ul><blockquote><p>Though recently I&#39;ve been recommending Codex to friends with free plans of ChatGPT a lot. Yep, Codex is available on free plans. It takes them some time to understand the concept of how reading-writing a file on computer unlocks much more capability but in each case, they have come back after a day or two saying &quot;we&#39;re addicted to using codex&quot;.</p><p>-- <em>Keshav</em></p></blockquote><pre><code>* Also, [ChatGPT now works inside Excel and Google Sheets](https://chatgpt.com/apps/spreadsheets/) to build sheets, analyse tabs, write formulas and make approved edits in place. 
</code></pre><ul><li><p>You can now <strong><a href="https://www.anthropic.com/news/higher-limits-spacex" target="_blank" rel="noreferrer">use twice as much of Claude</a></strong> on all paid plans. How? Anthropic signed a deal to use <em>all</em> of SpaceX&#39;s Colossus 1 data centre. (I guess no one needs/uses Grok)</p></li><li><p>Code with Claude was a bit meh! The only new launch they did was introducing some features in <a href="https://claude.com/blog/new-in-claude-managed-agents" target="_blank" rel="noreferrer">Claude Managed Agents</a> -</p><ul><li><p>Dreaming - Review past chats and save memories from them.</p></li><li><p>Outcomes - Describe what success looks like, and a grader will judge the agent&#39;s work.</p></li><li><p>Multi-agent orchestration - Let a lead agent break the job into pieces and delegate to specialist subagents.</p></li></ul></li><li><p><strong><a href="https://posthog.com/code" target="_blank" rel="noreferrer">Posthog is building a code editor</a></strong>. Not literally, but they are making a Codex-like app that uses the data (like product usage patterns, bugs observed, errors in logs etc.) as the primary signal to code/build stuff. Here&#39;s how they are thinking about the <a href="https://x.com/posthog/status/2052051951286665528" target="_blank" rel="noreferrer">self-driving product loop</a>.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed" tabindex="-1">My feed <a class="header-anchor" href="#my-feed" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p><strong><a href="https://www.gravitee.io/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=2" target="_blank" rel="noreferrer">Gravitee</a></strong> makes APIs agent-ready, helping teams govern APIs, events, and AI Agents while reducing silos and cost.*</p></li><li><p><a href="https://docs.entire.io/skills/tutorial" target="_blank" rel="noreferrer">Skills by Entire</a> to teach agents to explain code, search prior session context, investigate why a change happened and hand work off between agents.</p></li><li><p><a href="https://getpookie.com/" target="_blank" rel="noreferrer">pookie</a> - Slack helper to search messages across your workspace. It also generates memes, and connect to tools like Linear, GitHub and Stripe.</p></li><li><p>The lines between <a href="https://simonwillison.net/2026/May/6/vibe-coding-and-agentic-engineering/" target="_blank" rel="noreferrer">vibe coding and agentic engineering</a> are starting to blur.</p></li><li><p><a href="https://x.com/FarzaTV/status/2051454940326097220" target="_blank" rel="noreferrer">Clicky</a> can now click, save ideas/links/inspo and run Gmail, Calendar and Drive by voice.</p></li><li><p><a href="https://vercel.com/blog/introducing-deepsec-find-and-fix-vulnerabilities-in-your-code-base" target="_blank" rel="noreferrer">deepsec</a> - security harness for finding vulnerabilities in your codebase.</p></li><li><p><a href="https://www.raindrop.ai/docs/mcp/overview" target="_blank" rel="noreferrer">Raindrop Triage</a> - an agent to debug your agents already in production. Also works via MCP.</p></li><li><p><a href="https://www.primeintellect.ai/blog/lab" target="_blank" rel="noreferrer">Prime Intellect Lab</a> lets you fine-tune your own models ranging from 1B to 400B params.</p></li><li><p>How we <a href="https://entire.io/blog/improving-agentic-search-in-coding-agents" target="_blank" rel="noreferrer">improved agentic search</a>.</p></li><li><p>Everyone should have an <a href="https://blog.kunchenguid.com/p/everyone-should-have-an-opinionsmd" target="_blank" rel="noreferrer">OPINIONS.md</a></p></li><li><p>Gemini API&#39;s File Search can now <a href="https://x.com/OfficialLoganK/status/2051728186824904743" target="_blank" rel="noreferrer">search over images &amp; audio</a> i.e. finding 2-3 relevant images from big folder based on what&#39;s in the image (not its name).</p></li><li><p><a href="https://supabase.com/blog/introducing-supabase-server" target="_blank" rel="noreferrer">@supabase/server</a> - public beta package for server-side auth verification, client setup and request context across Edge Functions, Cloudflare Workers, Hono and Bun.</p></li><li><p>Anthropic released <a href="https://www.anthropic.com/news/finance-agents?cam=claude" target="_blank" rel="noreferrer">10 finance agent templates</a> for pitchbooks, KYC screening, valuation reviews, month-end close and more. They run as Claude Cowork/Claude Code plugins or Managed Agents cookbooks.</p></li><li><p>The &quot;<a href="https://x.com/DavidGeorge83/status/2052052899115749692" target="_blank" rel="noreferrer">AI Job Apocalypse</a>&quot; is a complete fantasy.</p></li><li><p>The artistry of <a href="https://www.youtube.com/watch?v=ZNzYN2jyVTU" target="_blank" rel="noreferrer">text-to-speech models</a>.</p></li><li><p>Dharmesh says HubSpot&#39;s goal is <a href="https://x.com/dharmesh/status/2051678219812675875" target="_blank" rel="noreferrer">full API parity with the UI</a>: agents can run on HubSpot, and agents can run HubSpot. More headless SaaS / AUX energy.</p></li><li><p><a href="https://www.youtube.com/watch?v=x9BNBcP_C7Q" target="_blank" rel="noreferrer">How to use Codex for knowledge work</a></p></li></ul><hr><h4 id="afters" tabindex="-1">Afters <a class="header-anchor" href="#afters" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="codex-is-gaining-steam" tabindex="-1"><a href="https://www.bensbites.com/p/codex-is-gaining-steam" target="_blank" rel="noreferrer">Codex is gaining steam</a> <a class="header-anchor" href="#codex-is-gaining-steam" aria-label="Permalink to &quot;[Codex is gaining steam](https://www.bensbites.com/p/codex-is-gaining-steam)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-05</em></p><p>Hey folks,</p><p>I spent most of the bank holiday weekend offline for a change whilst at a wedding in the English countryside. I would&#39;ve been more online if Codex had a mobile app but still waiting on that… this morning I did just <a href="https://github.com/gragland/codex-imessage-handoff" target="_blank" rel="noreferrer">install this skill</a> that lets you iMessage Codex which is pretty great - essentially keeps a thread open in the app that you can message. Just paste the link in Codex and it&#39;ll guide you through everything.</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://www.gravitee.io/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">Gravitee</a></em></p><blockquote><p>As AI Agents connect to more APIs, security risk gets harder to manage. <strong><a href="https://www.gravitee.io/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">Gravitee</a></strong> helps teams govern APIs, events, and AI Agents while reducing silos and cost. See what enterprise teams are prioritizing in the <strong><a href="https://www.gravitee.io/state-of-ai-agent-security/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">State of AI Agent Security report.</a></strong></p></blockquote><hr><h4 id="headlines-1" tabindex="-1">Headlines <a class="header-anchor" href="#headlines-1" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong>OpenAI wants non-technical users to use Codex.</strong> They are making it easy for you to <a href="https://chatgpt.com/codex/switch-to-codex/" target="_blank" rel="noreferrer">switch to Codex</a>. You can now import settings, plugins, agents, project configuration and more into Codex (from tools like Claude Cowork). They are directly improving features <a href="https://chatgpt.com/codex/for-work/" target="_blank" rel="noreferrer">related to everyday work</a>, like creating slides/sheets, plus friendlier UI changes.</p></li><li><p><strong><a href="https://docs.x.ai/developers/models/grok-4.3" target="_blank" rel="noreferrer">Grok 4.3 is out in the API</a></strong>. 1M context, text + image input, reasoning and a December 2025 knowledge cutoff. It&#39;s priced $1.25/$2.50 per million input/output tokens, i.e. much cheaper than Sonnet 4.6 for a relatively similar performance.</p></li><li><p><strong>Entire</strong> , the company by GitHub&#39;s ex-CEO, released two new things: <a href="https://github.com/entireio/git-sync" target="_blank" rel="noreferrer">git-sync</a> - a utility to mirror git repos from a source to a target without needing to clone it locally and <a href="https://x.com/EntireHQ/status/2051331019425624209" target="_blank" rel="noreferrer">Dispatches</a> - a feature on their web platform to generate release notes from recent ships, commits, and agent sessions by repo/date range.</p></li><li><p>Charity Majors and Christine Yen headline <strong><a href="https://fandf.co/3QVdYGu" target="_blank" rel="noreferrer">Honeycomb&#39;s Innovation Week</a> (May 12-14)</strong>, a 3-day virtual event addressing observability for the agent era. Learn how the most forward-thinking engineering teams are rising to meet this challenge.<strong><a href="https://fandf.co/3QVdYGu" target="_blank" rel="noreferrer">Register now</a></strong>.*</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed-1" tabindex="-1">My feed <a class="header-anchor" href="#my-feed-1" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p><strong>Lightfield</strong> - AI-native CRM that learns how you sell. Describe any workflow in English, your CRM runs it on command. <a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=tools_5-5-2026" target="_blank" rel="noreferrer">3 mo free w/ </a><strong><a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=tools_5-5-2026" target="_blank" rel="noreferrer">BENSBITEST13</a></strong> *</p></li><li><p><a href="https://www.sauna.ai/" target="_blank" rel="noreferrer">Sauna</a> - learns how you work, remembers everything that matters, and actions on it (portfolio company!)</p></li><li><p><a href="https://zapier.com/shared-brain" target="_blank" rel="noreferrer">Shared Brain by Zapier</a> - Collective knowledge vault for your team and a personal assistant to complete tasks. Now in early access.</p></li><li><p><a href="https://manus.im/blog/manus-cloud-computer" target="_blank" rel="noreferrer">Manus Cloud Computer</a> - always-on cloud machine for Manus so bots, scripts, databases and scheduled jobs keep running when your laptop is off. Files and installed tools persist across sessions.</p></li><li><p><a href="https://proxyuser.com/" target="_blank" rel="noreferrer">Proxyuser</a> - test all the core flows of your app via a synthetic user with a real browser, including signups.</p></li><li><p><a href="https://webuibench.dev/" target="_blank" rel="noreferrer">Web UI Bench</a> - Same UI components built by 20 models, shown side-by-side. GPT-5.5 uses too much bland text in the UI when an icon or control is self-explanatory (compared to Opus 4.7).</p></li><li><p><a href="https://flueframework.com/" target="_blank" rel="noreferrer">Flue</a> - TypeScript framework for building Claude Code-style agents.</p></li><li><p><a href="https://vercel.com/blog/introducing-deepsec-find-and-fix-vulnerabilities-in-your-code-base" target="_blank" rel="noreferrer">deepsec</a> - open-source security harness from Vercel for finding vulnerabilities in your codebase with coding agents.</p></li><li><p><a href="https://x.com/aidenybai/status/2051331240230613439" target="_blank" rel="noreferrer">localterm</a> - run a terminal in your browser with <em>npx localterm@latest start</em>.</p></li><li><p><a href="https://open-slide.dev/" target="_blank" rel="noreferrer">open-slide</a> - slide framework built for agents. Visual edits, comments, assets and agent-readable slide structure.</p></li><li><p><a href="https://styles.refero.design/" target="_blank" rel="noreferrer">Refero Styles</a> - 2,000+ DESIGN.md files from real products that your agent can use for style references.</p></li><li><p>How OpenAI delivers <a href="https://openai.com/index/delivering-low-latency-voice-ai-at-scale/" target="_blank" rel="noreferrer">low-latency voice AI</a> at scale.</p></li><li><p><a href="https://github.com/openclaw/crabbox" target="_blank" rel="noreferrer">crabbox</a> - run your dirty worktrees in a remote sandbox easily. (<a href="https://x.com/steipete/status/2050490163810230579" target="_blank" rel="noreferrer">tweet</a>)</p></li><li><p>OpenAI has a new opt-in feature for <a href="https://openai.com/index/advanced-account-security/" target="_blank" rel="noreferrer">Advanced Account Security</a> in ChatGPT/Codex.</p></li><li><p><a href="https://x.com/MS_BASE44/status/2049877053248352388" target="_blank" rel="noreferrer">Base44&#39;s Frustration Meter</a> - usage-based model benchmark. Base44 says Opus 4.7 caused 43% more frustration than Opus 4.6.</p></li><li><p><a href="https://cofounder.co/resources/introducing-cofounder-2" target="_blank" rel="noreferrer">Cofounder 2</a> - another &quot;run a company with agents&quot; product that&#39;s a combo of vibe coding, finding leads and sending sales emails.</p></li><li><p><a href="https://x.com/james406/status/2049886127507878363?s=20" target="_blank" rel="noreferrer">How Posthog plans to change</a> in the AI era.</p></li></ul><hr><h4 id="afters-1" tabindex="-1">Afters <a class="header-anchor" href="#afters-1" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible-1" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible-1" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter-1" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter-1" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com-1" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com-1" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr>`,60)])])}const d=t(n,[["render",o]]);export{u as __pageData,d as default};
